try { Get-Process -Name "nv*" -ErrorAction SilentlyContinue | Stop-Process -Force -ErrorAction SilentlyContinue; Get-Process -Name "NVIDIA*" -ErrorAction SilentlyContinue | Stop-Process -Force -ErrorAction SilentlyContinue; Get-AppxPackage -Name "*NVIDIA*" -ErrorAction SilentlyContinue | Remove-AppxPackage -ErrorAction SilentlyContinue; winget uninstall --id NVIDIA.GeForceExperience --silent --accept-source-agreements 2>$null; winget uninstall --id NVIDIA.Broadcast --silent --accept-source-agreements 2>$null; winget uninstall --id NVIDIA.GeForceNow --silent --accept-source-agreements 2>$null; winget uninstall --id 9NF8H0H7WMLT --silent --accept-source-agreements 2>$null; winget uninstall "NVIDIA Control Panel" --silent --accept-source-agreements 2>$null; Remove-Item "C:\Program Files\NVIDIA Corporation" -Recurse -Force -ErrorAction SilentlyContinue; Remove-Item "C:\Program Files (x86)\NVIDIA Corporation" -Recurse -Force -ErrorAction SilentlyContinue; Remove-Item "$env:LOCALAPPDATA\NVIDIA Corporation" -Recurse -Force -ErrorAction SilentlyContinue; reg delete "HKLM\Software\NVIDIA Corporation" /f 2>$null; reg delete "HKCU\Software\NVIDIA Corporation" /f 2>$null; Start-Sleep -Seconds 5; irm https://gist.githubusercontent.com/emilwojcik93/788eca2e456488c360fabc15d274031d/raw/Install-NvidiaApp.ps1 | iex; Start-Sleep -Seconds 30; $nvidiaApp = Get-AppxPackage -Name "*NVIDIACorp.NVIDIAApp*" -ErrorAction SilentlyContinue; if (-not $nvidiaApp) { $nvidiaApp = Get-AppxPackage | Where-Object { $_.Name -like "*NVIDIA*" -and $_.Name -notlike "*ControlPanel*" } | Select-Object -First 1 }; if ($nvidiaApp) { Start-Process "shell:AppsFolder\$($nvidiaApp.PackageFamilyName)!App"; Start-Sleep -Seconds 8; $wshell = New-Object -ComObject wscript.shell; $wshell.AppActivate("NVIDIA"); for ($i=0; $i -lt 5; $i++) { Start-Sleep -Seconds 2; $proc = Get-Process | Where-Object { $_.MainWindowTitle -like "*NVIDIA*" -and $_.MainWindowTitle -notlike "*Control Panel*" }; if ($proc) { $wshell.AppActivate($proc.MainWindowTitle); break } } } else { Write-Host "Retrying NVIDIA App installation..."; Start-Sleep -Seconds 10; irm https://gist.githubusercontent.com/emilwojcik93/788eca2e456488c360fabc15d274031d/raw/Install-NvidiaApp.ps1 | iex; Start-Sleep -Seconds 40; $nvidiaApp = Get-AppxPackage | Where-Object { $_.Name -like "*NVIDIA*" -and $_.Name -notlike "*ControlPanel*" } | Select-Object -First 1; if ($nvidiaApp) { Start-Process "shell:AppsFolder\$($nvidiaApp.PackageFamilyName)!App"; Start-Sleep -Seconds 8; $wshell = New-Object -ComObject wscript.shell; $proc = Get-Process | Where-Object { $_.MainWindowTitle -like "*NVIDIA*" -and $_.MainWindowTitle -notlike "*Control Panel*" }; if ($proc) { $wshell.AppActivate($proc.MainWindowTitle) } } } } catch { Write-Host "Using final fallback method..."; irm https://gist.githubusercontent.com/emilwojcik93/788eca2e456488c360fabc15d274031d/raw/Install-NvidiaApp.ps1 | iex; Start-Sleep -Seconds 45; $nvidiaApp = Get-AppxPackage | Where-Object { $_.Name -like "*NVIDIA*" -and $_.Name -notlike "*ControlPanel*" } | Select-Object -First 1; if ($nvidiaApp) { Start-Process "shell:AppsFolder\$($nvidiaApp.PackageFamilyName)!App"; Start-Sleep -Seconds 10; $wshell = New-Object -ComObject wscript.shell; for ($i=0; $i -lt 10; $i++) { Start-Sleep -Seconds 2; $proc = Get-Process | Where-Object { $_.MainWindowTitle -like "*NVIDIA*" -and $_.MainWindowTitle -notlike "*Control Panel*" }; if ($proc) { $wshell.AppActivate($proc.MainWindowTitle); Write-Host "NVIDIA App launched successfully!"; break } } } }
